vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vec2 tmp = vUv;
float dist = 1;
float inten = 1;
float mask = 0;
ret1 = 0;
int anz = 3;
float n = 0;
float t_rel = q29;
while (n <= anz) {
    ang2 = 6.28*n/anz+q30;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2*= uAspect.yx;

    dist = 1-fract(n/anz+t_rel); //evtl sqrt !

    inten =  4*dist*(1-dist*dist);
    uv3 = 3*uv2*dist + 0.5+.0*vec2(q5,q6);
    crisp = GetPixel(uv3);
    blur = GetBlur1(fract(uv3)) * vec3 (.8,.9,1);
    ret1 = max(ret1,(crisp+blur)*inten);
n++;
}


vec3 ret1 = ret1 ;
//ret1 = GetPixel(.5+vUvOriginal*uAspect.yx*1.2);


ret = ret1-.1;


  fragColor = ret;
}
